parameters.jsCode:
const originalInput = $('Set - Prepare Code Context').item.json;
const current = $input.item.json;

let aiOutput =
  current.output ||
  current.text ||
  current.message ||
  current.content ||
  current.data ||
  current;

if (typeof aiOutput === 'string') {
  aiOutput = aiOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    aiOutput = JSON.parse(aiOutput);
  } catch (error) {
    aiOutput = {
      wf03_code_assistance: {
        implementation_strategy: 'AI output could not be parsed as valid JSON.',
        refactoring_recommendations: [],
        files_to_create: [],
        files_to_modify: [],
        pseudo_code: '',
        patch_proposal: '',
        unit_test_suggestions: [],
        integration_test_suggestions: [],
        git_actions: {
          suggested_branch_name: '',
          commit_message: '',
          pull_request_title: '',
          pull_request_description: ''
        },
        risks: ['Invalid JSON returned by the AI agent.'],
        requires_human_approval: true,
        ready_for_qa: false
      }
    };
  }
}

const assistance = aiOutput.wf03_code_assistance || aiOutput;

return {
  json: {
    ...originalInput,
    wf03_code_assistance: {
      implementation_strategy: assistance.implementation_strategy || '',
      refactoring_recommendations: Array.isArray(assistance.refactoring_recommendations) ? assistance.refactoring_recommendations : [],
      files_to_create: Array.isArray(assistance.files_to_create) ? assistance.files_to_create : [],
      files_to_modify: Array.isArray(assistance.files_to_modify) ? assistance.files_to_modify : [],
      pseudo_code: assistance.pseudo_code || '',
      patch_proposal: assistance.patch_proposal || '',
      unit_test_suggestions: Array.isArray(assistance.unit_test_suggestions) ? assistance.unit_test_suggestions : [],
      integration_test_suggestions: Array.isArray(assistance.integration_test_suggestions) ? assistance.integration_test_suggestions : [],
      git_actions: assistance.git_actions || {
        suggested_branch_name: '',
        commit_message: '',
        pull_request_title: '',
        pull_request_description: ''
      },
      risks: Array.isArray(assistance.risks) ? assistance.risks : [],
      requires_human_approval: true,
      ready_for_qa: Boolean(assistance.ready_for_qa)
    }
  }
};
